// 2 次元 char 配列を文字列リテラルの並びで初期化する `char a[2][6]={"hello","world"}`
// が壊れていた (各文字列が行を埋めず、スカラ要素/ポインタとして誤処理)。ローカル・
// グローバル両経路で、各文字列が行 (row 幅) のバイト列を埋め残りを 0 にするよう修正。
#include <assert.h>

char g[2][6] = { "hello", "world" };
char gp[3][4] = { "ab", "cde" };   /* 部分行 + 0 埋め */

int main(void) {
    /* グローバル */
    assert(g[0][0] == 'h' && g[0][4] == 'o' && g[0][5] == 0);
    assert(g[1][0] == 'w' && g[1][4] == 'd');
    assert(gp[0][0] == 'a' && gp[0][1] == 'b' && gp[0][2] == 0);
    assert(gp[1][2] == 'e' && gp[1][3] == 0);

    /* ローカル */
    char a[2][6] = { "hello", "world" };
    assert(a[0][0] == 'h' && a[0][4] == 'o' && a[0][5] == 0);
    assert(a[1][0] == 'w' && a[1][4] == 'd');

    char b[3][4] = { "ab", "cde" };
    assert(b[0][0] == 'a' && b[0][2] == 0);
    assert(b[1][2] == 'e' && b[1][3] == 0);
    assert(b[2][0] == 0);   /* 未指定行は 0 */

    /* char* 配列 (回帰しないこと) */
    char *p[2] = { "xy", "zw" };
    assert(p[0][0] == 'x' && p[1][1] == 'w');
    return 0;
}
